import { IconButton, Typography } from "@mui/material";
import InstagramIcon from "@mui/icons-material/Instagram";
import LinkedInIcon from "@mui/icons-material/LinkedIn";
import GitHubIcon from "@mui/icons-material/GitHub";
import Stack from "@mui/material/Stack";
import { styled } from "@mui/material/styles";
import { useState } from "react";

const StyledFooter = styled('footer')`
  ${({ theme }) => `
    display: flex;
    justify-content: center;
    align-items: center;
    margin-top: 16px;
    flex-direction: column;
    opacity: ${props => props.visible ? '1' : '0'}; // Initially hidden
    transform: translateX(${props => props.visible ? '0' : '-100px'}); // Initially translate -100px to the left
    transition: opacity 1s ease-in-out, transform 1s ease-in-out; // Longer transition duration
  `}
`;

export const Footer = () => {
    const [visible, setVisible] = useState(false);

    // Function to toggle visibility of the footer
    const toggleFooter = () => {
      setVisible(prevVisible => !prevVisible);
    };
  return (
      <StyledFooter visible={visible}>
        <Typography variant="h4">Lets Get in Touch</Typography>
        <Stack direction="row" spacing={1}>
          <IconButton sx={{ color: "#fff" }} aria-label="LinkedIn">
            <LinkedInIcon />
          </IconButton>
          <IconButton color="secondary" aria-label="GitHub">
            <GitHubIcon />
          </IconButton>
          <IconButton color="primary" aria-label="Instagram">
            <InstagramIcon />
          </IconButton>
        </Stack>
      </StyledFooter>
  );
};
